import React, { useState, useMemo } from 'react';
import { useApp } from '../contexts/AppContext';
import { ChevronUp, ChevronDown, Receipt } from 'lucide-react';

export default function Faturamento() {
  const { vendas, loading } = useApp();
  const [busca, setBusca] = useState('');
  const [sortConfig, setSortConfig] = useState({ key: 'id', direction: 'desc' });

  // Filtro por ID do Pedido com tratamento de erros
  const vendasFiltradas = useMemo(() => {
    // 1. Verificação de segurança: Se 'vendas' não existir ou não for array, retorna vazio
    if (!vendas || !Array.isArray(vendas)) return [];

    let result = vendas.filter(v => {
      // Se não houver busca, mantém o item
      if (!busca.trim()) return true;

      // 2. Verificação de segurança: Se o objeto venda ou o ID não existirem, ignora
      if (!v || v.id === undefined || v.id === null) return false;
      
      // Filtra pelo ID convertido em string
      return v.id.toString().includes(busca);
    });

    // Lógica de Ordenação
    if (sortConfig.key) {
      result.sort((a, b) => {
        const valA = a[sortConfig.key] ?? '';
        const valB = b[sortConfig.key] ?? '';
        
        if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
        if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
        return 0;
      });
    }
    return result;
  }, [vendas, busca, sortConfig]);

  const handleSort = (key) => {
    setSortConfig(prev => ({
      key,
      direction: prev.key === key && prev.direction === 'asc' ? 'desc' : 'asc'
    }));
  };

  if (loading) return <div className="mt-24 text-center animate-pulse text-blue-600 font-semibold">Carregando faturamento...</div>;

  return (
    <main className="mt-24 container mx-auto p-4">
      <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4">
        <h2 className="text-2xl font-bold flex items-center gap-2 text-gray-800">
          <Receipt className="text-blue-600" /> Histórico de Vendas
        </h2>
        <input 
          type="text" 
          placeholder="Buscar pelo número do pedido..." 
          className="border p-2 rounded-lg w-full md:w-80 shadow-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all"
          value={busca}
          onChange={(e) => setBusca(e.target.value)}
        />
      </div>

      <div className="overflow-x-auto bg-white rounded-xl shadow-lg border border-gray-100">
        <table className="w-full text-left">
          <thead className="bg-gray-50 border-b">
            <tr>
              {[
                { label: 'Pedido', key: 'id' },
                { label: 'Data', key: 'data' },
                { label: 'Valor Total', key: 'valor_total' }
              ].map((column) => (
                <th 
                  key={column.key} 
                  className="p-4 cursor-pointer hover:bg-gray-100 transition group" 
                  onClick={() => handleSort(column.key)}
                >
                  <div className="flex items-center gap-1 text-xs font-bold text-gray-500 uppercase tracking-wider">
                    {column.label}
                    <span className="opacity-0 group-hover:opacity-100 transition-opacity">
                      {sortConfig.key === column.key ? (
                        sortConfig.direction === 'asc' ? <ChevronUp size={14}/> : <ChevronDown size={14}/>
                      ) : <ChevronDown size={14} className="text-gray-300"/>}
                    </span>
                  </div>
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {vendasFiltradas.length > 0 ? (
              vendasFiltradas.map(venda => (
                <tr key={venda.id} className="hover:bg-blue-50/50 transition-colors">
                  <td className="p-4 font-medium text-blue-600">#{venda.id}</td>
                  <td className="p-4 text-gray-600">
                    {venda.data ? new Date(venda.data).toLocaleDateString('pt-BR') : '---'}
                  </td>
                  <td className="p-4 font-bold text-green-600">
                    {venda.valor_total ? `R$ ${venda.valor_total.toFixed(2)}` : 'R$ 0,00'}
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="3" className="p-10 text-center text-gray-400 italic">
                  Nenhuma venda encontrada para os critérios de busca.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </main>
  );
}
